'use strict';

const section = require('./section.cjs');
const text = require('./text.cjs');

function createThumbArea(argA, argB) {
  const data = typeof argA === "string" ? { content: argA, thumbnail: argB } : argA;
  return data.thumbnail ? section.createSection(data.content, data.thumbnail) : text.createTextDisplay(data.content);
}

exports.createThumbArea = createThumbArea;
